import { TrafficLightStatus, UserProgress, MasterPlan } from '../types';

/**
 * R2: Motor de Ingesta Inteligente
 * Regla "OPAR-VPO"
 */
export const cleanCode = (code: string): string => {
  return code.replace(/PAP-OPAR-(\d+)/g, 'PAP-VPO-$1');
};

/**
 * R3: Semáforo de Estado (Cálculo Diario)
 */
export const calculateTrafficLight = (
  progress: UserProgress,
  plan: MasterPlan
): TrafficLightStatus => {
  const startDate = new Date(progress.fecha_inicio);
  const endDate = new Date(startDate);
  endDate.setDate(startDate.getDate() + plan.duracion_dias);

  const today = new Date();

  // RED (Atrasado): (Fecha Actual > Fecha Fin) Y (Progreso < 100%)
  if (today > endDate && progress.progreso_porcentaje < 100) {
    return TrafficLightStatus.RED;
  }

  // YELLOW (Riesgo): Si el usuario lleva > 3 días sin actividad registrada
  const lastActivity = new Date(progress.ultima_actividad);
  const diffTime = Math.abs(today.getTime() - lastActivity.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  if (diffDays > 3) {
    return TrafficLightStatus.YELLOW;
  }

  return TrafficLightStatus.GREEN;
};

/**
 * Calculates remaining days
 */
export const getRemainingDays = (startDateStr: string, duration: number): number => {
  const start = new Date(startDateStr);
  const end = new Date(start);
  end.setDate(start.getDate() + duration);
  const today = new Date();
  const diffTime = end.getTime() - today.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

import { GoogleGenAI, Type } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export async function smartIngest(rawText: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: `
      Act as a Farmatodo Data Ingestion Specialist. 
      Analyze the following raw text extracted from a training plan document.
      Apply business rule R2: If you find codes like "PAP-OPAR-XXX", convert them to "PAP-VPO-XXX".
      Extract modules and tasks.

      Raw Text:
      ${rawText}

      Return the data in a structured JSON format following the schema:
      {
        "id_plan": "detected_id",
        "cargo_target": "detected_cargo",
        "duracion_dias": number,
        "modulos": [
          {
            "titulo": "string",
            "tipo_modulo": "ESTANDAR",
            "tareas": [
              { "descripcion": "string", "recurso_ref": "VPO_CODE_HERE", "obligatorio": true }
            ]
          }
        ]
      }
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id_plan: { type: Type.STRING },
          cargo_target: { type: Type.STRING },
          duracion_dias: { type: Type.NUMBER },
          modulos: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                titulo: { type: Type.STRING },
                tipo_modulo: { type: Type.STRING },
                tareas: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      descripcion: { type: Type.STRING },
                      recurso_ref: { type: Type.STRING },
                      obligatorio: { type: Type.BOOLEAN }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  });

  return JSON.parse(response.text);
}

