import React, { useState } from 'react';
import { User, MasterPlan, UserProgress, ResourceType, Resource } from '../types';
import { IconFile, IconPlay, IconLink, IconCheck, IconChevronDown, IconAlert } from './Icons';
import { calculateTrafficLight, getRemainingDays } from '../utils/logic';

interface Props {
  user: User;
  plan: MasterPlan;
  progress: UserProgress;
  resources: Resource[];
  onCheckTask: (resourceId: string) => void;
}

const CollaboratorView: React.FC<Props> = ({ user, plan, progress, resources, onCheckTask }) => {
  const [expandedModules, setExpandedModules] = useState<Record<string, boolean>>({ 'Caja Registradora': true });

  const toggleModule = (title: string) => {
    setExpandedModules(prev => ({ ...prev, [title]: !prev[title] }));
  };

  const getResourceIcon = (type?: ResourceType) => {
    switch (type) {
      case ResourceType.VIDEO: return <IconPlay />;
      case ResourceType.ENCUESTA: return <IconLink />;
      default: return <IconFile />;
    }
  };

  const status = calculateTrafficLight(progress, plan);
  const statusColors = {
    RED: 'bg-red-500',
    YELLOW: 'bg-yellow-500',
    GREEN: 'bg-green-500'
  };

  const remaining = getRemainingDays(progress.fecha_inicio, plan.duracion_dias);

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      {/* Header Profile */}
      <div className="bg-white rounded-xl shadow-sm p-6 flex flex-col md:flex-row md:items-center justify-between border border-gray-100">
        <div className="flex items-center space-x-4">
          <div className="h-16 w-16 bg-blue-100 rounded-full flex items-center justify-center text-blue-600 font-bold text-xl">
            {user.nombre.charAt(0)}
          </div>
          <div>
            <h1 className="text-xl font-bold text-gray-800">{user.nombre}</h1>
            <p className="text-gray-500 text-sm">{user.cargo} • {user.area}</p>
          </div>
        </div>

        <div className="mt-4 md:mt-0 flex flex-col items-end">
          <div className="flex items-center space-x-2 mb-1">
             <span className={`h-3 w-3 rounded-full ${statusColors[status]}`}></span>
             <span className="text-xs font-semibold text-gray-500 uppercase tracking-wider">
               {status === 'RED' ? 'Atrasado' : status === 'YELLOW' ? 'En Riesgo' : 'Al Día'}
             </span>
          </div>
          <p className="text-sm font-medium text-gray-600">
            {remaining > 0 ? `${remaining} días restantes` : 'Plazo vencido'}
          </p>
        </div>
      </div>

      {/* Progress Bar */}
      <div className="bg-white rounded-xl shadow-sm p-6 border border-gray-100">
        <div className="flex justify-between items-center mb-2">
          <h2 className="text-sm font-bold text-gray-700 uppercase tracking-tight">Progreso General</h2>
          <span className="text-lg font-black text-blue-600">{progress.progreso_porcentaje}%</span>
        </div>
        <div className="w-full bg-gray-100 rounded-full h-3">
          <div 
            className="bg-blue-600 h-3 rounded-full transition-all duration-500" 
            style={{ width: `${progress.progreso_porcentaje}%` }}
          ></div>
        </div>
      </div>

      {/* Modules Acordion */}
      <div className="space-y-4">
        {plan.modulos.map((module) => (
          <div key={module.titulo} className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <button 
              onClick={() => toggleModule(module.titulo)}
              className="w-full flex items-center justify-between p-4 hover:bg-gray-50 transition-colors"
            >
              <div className="flex items-center space-x-3">
                <span className="font-bold text-gray-800">{module.titulo}</span>
                <span className="px-2 py-0.5 bg-gray-100 text-[10px] font-bold text-gray-500 rounded uppercase">
                  {module.tipo_modulo}
                </span>
              </div>
              <div className={`${expandedModules[module.titulo] ? 'rotate-180' : ''} transition-transform`}>
                <IconChevronDown />
              </div>
            </button>

            {expandedModules[module.titulo] && (
              <div className="border-t border-gray-50 bg-white">
                <div className="divide-y divide-gray-50">
                  {module.tareas.map((task, idx) => {
                    const resource = resources.find(r => r.codigo === task.recurso_ref);
                    const isCompleted = progress.checks_completados.includes(task.recurso_ref);
                    const hasLink = !!resource?.url;

                    return (
                      <div key={idx} className="flex items-center justify-between p-4 hover:bg-blue-50/30 transition-colors">
                        <div className="flex items-center space-x-4 flex-1">
                          {/* Auto-check logic placeholder */}
                          <button 
                            onClick={() => onCheckTask(task.recurso_ref)}
                            className={`h-6 w-6 rounded border flex items-center justify-center transition-all ${
                              isCompleted 
                                ? 'bg-green-500 border-green-500 text-white' 
                                : 'bg-white border-gray-300 hover:border-blue-500'
                            }`}
                          >
                            {isCompleted && <IconCheck />}
                          </button>

                          <div className="flex-1">
                            <h4 className={`text-sm font-medium ${isCompleted ? 'text-gray-400 line-through' : 'text-gray-700'}`}>
                              {task.descripcion}
                            </h4>
                            <p className="text-[11px] text-gray-400 font-mono tracking-tight">{task.recurso_ref}</p>
                          </div>
                        </div>

                        <div className="flex items-center space-x-3">
                          <div className="text-gray-400">
                            {getResourceIcon(task.tipo_visual || resource?.tipo)}
                          </div>
                          <button 
                            disabled={!hasLink}
                            onClick={() => hasLink && window.open(resource?.url, '_blank')}
                            className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${
                              hasLink 
                                ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm' 
                                : 'bg-gray-100 text-gray-400 cursor-not-allowed'
                            }`}
                          >
                            {hasLink ? 'VER' : 'PENDIENTE'}
                          </button>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default CollaboratorView;

import React, { useState } from 'react';
import { IconUpload, IconAlert, IconCheck } from './Icons';
import { smartIngest } from '../services/geminiService';

const AdminView: React.FC = () => {
  const [isUploading, setIsUploading] = useState(false);
  const [log, setLog] = useState<string[]>([]);
  const [preview, setPreview] = useState<any>(null);

  const handleSimulateUpload = async () => {
    setIsUploading(true);
    setLog(['Iniciando lectura de archivo...', 'Aplicando Regla R2: Corrección OPAR a VPO...']);

    // Simulate a raw text extraction from a PDF/Excel
    const rawText = `
      PLAN: APV-VE-2025
      Cargo: Asistente Piso de Ventas
      Modulo: Caja
      - Apertura de Tienda (PAP-OPAR-200)
      - Manejo de Dinero (PAP-OPAR-210)
      - Servicio al Cliente (VIDEO-S-01)
      Duracion: 30 dias
    `;

    try {
      const result = await smartIngest(rawText);
      setPreview(result);
      setLog(prev => [
        ...prev, 
        'Corrección PAP-OPAR-200 detectada -> PAP-VPO-200',
        'Corrección PAP-OPAR-210 detectada -> PAP-VPO-210',
        'Cruces con biblioteca completados.',
        'Plan listo para publicación.'
      ]);
    } catch (err) {
      setLog(prev => [...prev, 'Error procesando archivo: ' + err]);
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
      <div className="bg-white p-8 rounded-2xl border-2 border-dashed border-gray-200 flex flex-col items-center justify-center space-y-4 hover:border-blue-400 transition-colors cursor-pointer group">
        <div className="bg-blue-50 p-4 rounded-full text-blue-600 group-hover:scale-110 transition-transform">
          <IconUpload />
        </div>
        <div className="text-center">
          <p className="text-lg font-bold text-gray-700">Arrastra tu Plan (.xlsx / .pdf)</p>
          <p className="text-sm text-gray-500">O haz clic para seleccionar archivos</p>
