        <button 
          onClick={handleSimulateUpload}
          className="mt-4 bg-blue-600 text-white px-6 py-2 rounded-xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-200"
        >
          SIMULAR CARGA MASIVA
        </button>
      </div>

      {isUploading && (
        <div className="flex items-center justify-center space-x-2 p-4 bg-blue-50 rounded-xl text-blue-700 font-bold">
          <div className="animate-spin h-4 w-4 border-2 border-blue-700 border-t-transparent rounded-full"></div>
          <span>Gemini AI analizando plan...</span>
        </div>
      )}

      {log.length > 0 && (
