          <p className="text-gray-500 mb-2">// LOG DE PROCESAMIENTO INTELIGENTE</p>
          {log.map((line, i) => (
            <p key={i}>[{new Date().toLocaleTimeString()}] > {line}</p>
          ))}
        </div>
      )}

      {preview && (
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 space-y-4 animate-in fade-in duration-700">
          <div className="flex justify-between items-center border-b pb-4">
            <h3 className="text-lg font-bold text-gray-800">Vista Previa del Plan Ingerido</h3>
            <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-black uppercase">Validado</span>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="p-3 bg-gray-50 rounded-lg">
              <p className="text-[10px] text-gray-400 font-bold uppercase">ID Plan</p>
              <p className="font-bold text-blue-600">{preview.id_plan}</p>
            </div>
            <div className="p-3 bg-gray-50 rounded-lg">
