const SupervisorView: React.FC<Props> = ({ user, progress }) => {
  const [evaluations, setEvaluations] = useState<Evaluation[]>([
    { competencia: 'Sentido de Urgencia', resultado: 'LOGRADO', feedback: 'Muy enfocado en la meta.' },
