    { competencia: 'Protocolo de Servicio', resultado: 'LOGRADO', feedback: 'Excelente trato.' }
  ]);

  const updateResult = (index: number, result: 'LOGRADO' | 'A_MEJORAR') => {
    const newEvals = [...evaluations];
    newEvals[index].resultado = result;
    setEvaluations(newEvals);
  };

  const updateFeedback = (index: number, text: string) => {
    const newEvals = [...evaluations];
    newEvals[index].feedback = text;
    setEvaluations(newEvals);
  };

  return (
    <div className="max-w-4xl mx-auto p-4 space-y-6">
