        <h2 className="text-xl font-bold text-gray-800 mb-1">Evaluación de Competencias Conductuales</h2>
        <p className="text-sm text-gray-500">Evaluando progreso de: <span className="font-bold text-blue-600">{user.nombre}</span></p>
      </div>

      <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-gray-100">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-gray-50 text-gray-500 text-[10px] font-black uppercase tracking-widest border-b">
              <th className="px-6 py-4">Competencia / Conducta</th>
              <th className="px-6 py-4 text-center">Estado</th>
              <th className="px-6 py-4">Feedback / Acciones</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {evaluations.map((ev, idx) => (
              <tr key={idx} className="hover:bg-gray-50/50 transition-colors">
                <td className="px-6 py-4">
                  <p className="text-sm font-bold text-gray-800">{ev.competencia}</p>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center justify-center space-x-4">
                    <label className="flex items-center space-x-2 cursor-pointer">
                      <input 
                        type="radio" 
                        name={`res-${idx}`}
                        checked={ev.resultado === 'LOGRADO'}
                        onChange={() => updateResult(idx, 'LOGRADO')}
                        className="w-4 h-4 text-blue-600"
                      />
                      <span className="text-xs font-bold text-green-600">Logrado</span>
                    </label>
                    <label className="flex items-center space-x-2 cursor-pointer">
                      <input 
                        type="radio" 
                        name={`res-${idx}`}
                        checked={ev.resultado === 'A_MEJORAR'}
                        onChange={() => updateResult(idx, 'A_MEJORAR')}
                        className="w-4 h-4 text-red-600"
                      />
                      <span className="text-xs font-bold text-red-600">A Mejorar</span>
                    </label>
                  </div>
                </td>
                <td className="px-6 py-4">
                  <textarea 
                    value={ev.feedback}
                    onChange={(e) => updateFeedback(idx, e.target.value)}
                    placeholder={ev.resultado === 'A_MEJORAR' ? "Obligatorio detallar mejora..." : "Opcional..."}
                    className={`w-full p-2 text-xs border rounded-lg focus:ring-2 focus:ring-blue-200 focus:border-blue-500 transition-all ${
                       ev.resultado === 'A_MEJORAR' && !ev.feedback ? 'border-red-300 bg-red-50' : 'border-gray-200'
                    }`}
                  />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="flex justify-end space-x-3">
        <button className="px-6 py-2 border border-gray-200 rounded-xl font-bold text-gray-500 hover:bg-gray-50">Cancelar</button>
        <button className="px-8 py-2 bg-blue-600 text-white rounded-xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-100">
          GUARDAR EVALUACIÓN
        </button>
      </div>
    </div>
  );
};

