import { GoogleGenAI, Type } from "@google/genai";

const MODEL_NAME = 'gemini-3-flash-preview';

export async function smartIngest(rawText: string) {
  // Always use a named parameter and process.env.API_KEY directly.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: `
      Act as a Farmatodo Data Ingestion Specialist. 
      Analyze the following raw text extracted from a training plan document.
      Apply business rule R2: If you find codes like "PAP-OPAR-XXX", convert them to "PAP-VPO-XXX".
      Extract modules and tasks.

      Raw Text:
      ${rawText}

      Return the data in a structured JSON format following the schema:
      {
        "id_plan": "detected_id",
        "cargo_target": "detected_cargo",
        "duracion_dias": number,
        "modulos": [
          {
            "titulo": "string",
            "tipo_modulo": "ESTANDAR",
            "tareas": [
              { "descripcion": "string", "recurso_ref": "VPO_CODE_HERE", "obligatorio": true }
            ]
          }
        ]
      }
    `,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id_plan: { type: Type.STRING },
          cargo_target: { type: Type.STRING },
          duracion_dias: { type: Type.NUMBER },
          modulos: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                titulo: { type: Type.STRING },
                tipo_modulo: { type: Type.STRING },
                tareas: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      descripcion: { type: Type.STRING },
                      recurso_ref: { type: Type.STRING },
                      obligatorio: { type: Type.BOOLEAN }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  });

  // Extract text output using the .text property (not a method).
  return JSON.parse(response.text);
}

