  COLABORADOR = 'COLABORADOR',
  SUPERVISOR_TIENDA = 'SUPERVISOR_TIENDA',
  SUPERVISOR_OFICINA = 'SUPERVISOR_OFICINA',
  ADMIN = 'ADMIN'
}

export enum UserArea {
  OPERACIONES = 'Operaciones',
  OFICINA = 'Oficina'
}

export interface User {
  id: string;
  nombre: string;
  apellido: string;
  cedula: string;
  pais: string;
  tienda: string;
  cargo: string;
  rol_sistema: UserRole;
  area: UserArea;
  fecha_ingreso: string;
  id_supervisor: string;
}

export enum ResourceType {
  PAP = 'PAP',
  VIDEO = 'VIDEO',
  CURSO = 'CURSO',
  ENCUESTA = 'ENCUESTA'
}

export interface Resource {
  codigo: string;
  nombre: string;
  tipo: ResourceType;
  url?: string;
  estado: 'ACTIVO' | 'INACTIVO';
}

export enum ModuloType {
  ESTANDAR = 'ESTANDAR',
  PERSONALIZADO = 'PERSONALIZADO'
}

export interface Task {
  descripcion: string;
  recurso_ref: string;
  obligatorio: boolean;
  tipo_visual?: ResourceType;
}

export interface Module {
  titulo: string;
  tipo_modulo: ModuloType;
  tareas: Task[];
}

export interface MasterPlan {
  id_plan: string;
  cargo_target: string;
  duracion_dias: number;
  modulos: Module[];
}

export enum PlanState {
  EN_PROCESO = 'EN_PROCESO', // Dentro del plazo, < 100%
  PENDIENTE = 'PENDIENTE',   // Plazo vencido, < 100%
  FORMADO = 'FORMADO',       // 100% y aprobado
  FALTA_APROBACION = 'FALTA_APROBACION' // 100% pero requiere validación
}

export interface Evaluation {
  competencia: string;
  resultado: 'LOGRADO' | 'A_MEJORAR';
  feedback: string;
}

export interface UserProgress {
  id_usuario: string;
  id_plan: string;
  fecha_inicio: string;
  estado_general: PlanState;
  progreso_porcentaje: number;
  checks_completados: string[];
  evaluaciones: Evaluation[];
  ultima_actividad: string;
}

export enum TrafficLightStatus {
  RED = 'RED',
  YELLOW = 'YELLOW',
  GREEN = 'GREEN'
}

