  const renderIndicadores = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* KPI Card */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-blue-600 p-6 rounded-3xl shadow-xl shadow-blue-200 text-white">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 opacity-80">Cumplimiento Global (KPI)</p>
          <h4 className="text-4xl font-black">{stats.kpi.toFixed(1)}%</h4>
          <p className="text-[10px] mt-2 font-bold opacity-60">Formados / (Formados + Pendientes)</p>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 text-gray-400">Total Formados</p>
          <h4 className="text-4xl font-black text-green-600">{stats.formados}</h4>
          <p className="text-[10px] mt-2 font-bold text-gray-300">Certificación completa</p>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 text-gray-400">Plazo Vencido</p>
          <h4 className="text-4xl font-black text-red-500">{stats.pendientes}</h4>
          <p className="text-[10px] mt-2 font-bold text-gray-300">Requieren intervención</p>
        </div>
      </div>

      {/* Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
          <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 mb-8">Efectividad por País</h3>
          <div className="space-y-6">
