import React, { useState, useEffect } from 'react';
import { User, UserRole, UserProgress, MasterPlan, Resource, PlanState } from './types';
import { mockUsers, mockPlans, mockResources, mockUserProgress } from './mockData';
import CollaboratorView from './components/CollaboratorView';
import AdminView from './components/AdminView';
import SupervisorView from './components/SupervisorView';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User>(mockUsers[0]);
  const [currentPlan] = useState<MasterPlan>(mockPlans[0]);
  const [userProgress, setUserProgress] = useState<UserProgress>(mockUserProgress[0]);
  const [allUserProgress, setAllUserProgress] = useState<UserProgress[]>(mockUserProgress);

  // Handle task completion
  const handleCheckTask = (resourceId: string) => {
    setUserProgress(prev => {
      const isAlreadyChecked = prev.checks_completados.includes(resourceId);
      const newChecks = isAlreadyChecked 
        ? prev.checks_completados.filter(id => id !== resourceId)
        : [...prev.checks_completados, resourceId];

      const totalTasks = currentPlan.modulos.reduce((acc, m) => acc + m.tareas.length, 0);
      const newProgress = Math.round((newChecks.length / totalTasks) * 100);

      const updatedProgress = {
        ...prev,
        checks_completados: newChecks,
        progreso_porcentaje: newProgress,
        ultima_actividad: new Date().toISOString()
      };

      // También actualizar en la lista general para que el supervisor vea cambios en tiempo real
      setAllUserProgress(currentAll => currentAll.map(p => p.id_usuario === prev.id_usuario ? updatedProgress : p));

      return updatedProgress;
    });
  };

  // Sidebar Role Switcher for POC demonstration
  const renderRoleSwitcher = () => (
    <div className="fixed bottom-6 right-6 bg-white/80 backdrop-blur-md p-2 rounded-2xl shadow-2xl border border-white/50 z-50 flex items-center space-x-2">
      <span className="text-[10px] font-black text-gray-400 px-3 uppercase tracking-widest">POC Role:</span>
      {mockUsers.filter(u => u.rol_sistema !== UserRole.COLABORADOR || u.id === 'user_001').map(user => (
        <button
          key={user.id}
          onClick={() => setCurrentUser(user)}
          className={`px-3 py-1.5 rounded-xl text-[10px] font-bold transition-all ${
            currentUser.id === user.id 
              ? 'bg-blue-600 text-white shadow-lg' 
              : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
          }`}
        >
          {user.rol_sistema === UserRole.ADMIN ? 'ADMIN' : user.rol_sistema === UserRole.SUPERVISOR_TIENDA ? 'SUPERVISOR' : 'COLABORADOR'}
        </button>
      ))}
    </div>
  );

  const renderContent = () => {
    switch (currentUser.rol_sistema) {
      case UserRole.ADMIN:
        return <AdminView />;
      case UserRole.SUPERVISOR_TIENDA:
      case UserRole.SUPERVISOR_OFICINA:
        return (
          <SupervisorView 
            supervisor={currentUser}
            allUsers={mockUsers}
            allProgress={allUserProgress} 
            plan={currentPlan}
            resources={mockResources}
          />
        );
      default:
        return (
          <CollaboratorView 
            user={currentUser} 
            plan={currentPlan} 
            progress={userProgress} 
            resources={mockResources}
            onCheckTask={handleCheckTask}
          />
        );
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-gray-900 pb-24">
      {/* Navigation */}
      <nav className="bg-white border-b border-gray-100 sticky top-0 z-40 backdrop-blur-sm bg-white/90">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="h-8 w-8 bg-blue-600 rounded-lg flex items-center justify-center">
               <span className="text-white font-black text-sm">FT</span>
            </div>
            <div>
              <span className="font-black text-blue-900 tracking-tighter text-lg uppercase">Carpeta Azul</span>
              <span className="ml-2 text-xs font-bold text-gray-400 bg-gray-100 px-2 py-0.5 rounded uppercase">POC v1.0</span>
            </div>
          </div>
          <div className="flex items-center space-x-4">
             <div className="text-right hidden sm:block">
                <p className="text-xs font-black text-gray-800">{currentUser.nombre} {currentUser.apellido}</p>
                <p className="text-[10px] text-blue-500 font-bold tracking-tight">{currentUser.rol_sistema}</p>
             </div>
             <div className="h-10 w-10 bg-gray-100 rounded-xl overflow-hidden border-2 border-white shadow-sm">
                <img src={`https://picsum.photos/seed/${currentUser.id}/100/100`} alt="Avatar" />
             </div>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <main className="py-8">
        <div className="max-w-6xl mx-auto px-4">
          <div className="mb-8">
            <h1 className="text-3xl font-black text-blue-950 tracking-tight">
              {currentUser.rol_sistema === UserRole.ADMIN ? 'Gestión de Capacitación' : 
               currentUser.rol_sistema.startsWith('SUPERVISOR') ? 'Panel del Supervisor' : 
               'Mi Plan de Entrenamiento'}
            </h1>
            <p className="text-gray-500 font-medium">
               {currentUser.rol_sistema === UserRole.ADMIN ? 'Control maestro de planes y recursos regionales.' : 
               currentUser.rol_sistema.startsWith('SUPERVISOR') ? `Gestión de equipo en ${currentUser.tienda}.` : 
               'Completa tus tareas para certificarte como APV Farmatodo.'}
            </p>
          </div>

          {renderContent()}
        </div>
      </main>

      {renderRoleSwitcher()}
    </div>
  );
};

