  { id_usuario: 'user_003', id_plan: 'PLAN-APV-SR-2025', fecha_inicio: '2025-02-01', estado_general: PlanState.FALTA_APROBACION, progreso_porcentaje: 100, checks_completados: [], evaluaciones: [], ultima_actividad: '2025-02-18' },
  { id_usuario: 'user_004', id_plan: 'PLAN-APV-SR-2025', fecha_inicio: '2024-11-01', estado_general: PlanState.FORMADO, progreso_porcentaje: 100, checks_completados: [], evaluaciones: [], ultima_actividad: '2025-02-01' },
  { id_usuario: 'user_005', id_plan: 'PLAN-APV-SR-2025', fecha_inicio: '2025-02-10', estado_general: PlanState.EN_PROCESO, progreso_porcentaje: 5, checks_completados: [], evaluaciones: [], ultima_actividad: '2025-02-11' },
];

import React, { useState, useMemo } from 'react';
import { IconUpload, IconAlert, IconCheck, IconFile, IconPlay, IconChevronDown } from './Icons';
import { smartIngest } from '../services/geminiService';
import { mockUsers, mockUserProgress, mockPlans } from '../mockData';
import { PlanState, UserArea } from '../types';

type AdminModule = 'COLABORADORES' | 'INDICADORES' | 'PLANES' | 'INGESTA';

const AdminView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<AdminModule>('COLABORADORES');
  const [isUploading, setIsUploading] = useState(false);
  const [ingestLog, setIngestLog] = useState<string[]>([]);
  const [ingestPreview, setIngestPreview] = useState<any>(null);

  // --- ESTADOS DE FILTROS ---
  const [filters, setFilters] = useState({
    pais: 'Todos',
    unidadNegocio: 'Todos',
    area: 'Todos',
    tienda: 'Todos',
    cargo: 'Todos',
    cedula: ''
  });

  const handleFilterChange = (key: string, value: string) => {
    setFilters(prev => ({ ...prev, [key]: value }));
  };

  // Listas para los selects basadas en los datos
  const uniqueList = (key: keyof typeof mockUsers[0]) => 
    ['Todos', ...Array.from(new Set(mockUsers.map(u => u[key] as string)))];

  // --- LOGICA MODULO COLABORADORES ---
  const collaboratorsData = useMemo(() => {
    return mockUsers.filter(u => u.rol_sistema === 'COLABORADOR').map(user => {
      const progress = mockUserProgress.find(p => p.id_usuario === user.id);
      return { ...user, progress };
    }).filter(u => {
      const matchesPais = filters.pais === 'Todos' || u.pais === filters.pais;
      const matchesCedula = !filters.cedula || u.cedula.toLowerCase().includes(filters.cedula.toLowerCase());
      return matchesPais && matchesCedula;
    });
  }, [filters.pais, filters.cedula]);

  // --- LOGICA MODULO INDICADORES ---
  const stats = useMemo(() => {
    // 1. Filtrar usuarios según los filtros activos
    const filteredUsers = mockUsers.filter(u => {
      if (u.rol_sistema !== 'COLABORADOR') return false;
      if (filters.pais !== 'Todos' && u.pais !== filters.pais) return false;
      if (filters.unidadNegocio !== 'Todos' && u.unidad_negocio !== filters.unidadNegocio) return false;
      if (filters.area !== 'Todos' && u.area !== filters.area) return false;
      if (filters.tienda !== 'Todos' && u.tienda !== filters.tienda) return false;
      if (filters.cargo !== 'Todos' && u.cargo !== filters.cargo) return false;
      if (filters.cedula && !u.cedula.toLowerCase().includes(filters.cedula.toLowerCase())) return false;
      return true;
    });

    const userIds = filteredUsers.map(u => u.id);
    const relevantProgress = mockUserProgress.filter(p => userIds.includes(p.id_usuario));

    // KPI = Formados / (Formados + Pendientes). Excluye "En Proceso" y "Falta Aprobación".
    const formados = relevantProgress.filter(p => p.estado_general === PlanState.FORMADO).length;
    const pendientes = relevantProgress.filter(p => p.estado_general === PlanState.PENDIENTE).length;
    const enProceso = relevantProgress.filter(p => p.estado_general === PlanState.EN_PROCESO).length;
    const faltaAprobacion = relevantProgress.filter(p => p.estado_general === PlanState.FALTA_APROBACION).length;

    const totalCalculable = formados + pendientes;
    const kpi = totalCalculable > 0 ? (formados / totalCalculable) * 100 : 0;

    // Agrupación por país para gráfico
    const paises = Array.from(new Set(filteredUsers.map(u => u.pais)));
    const statsPorPais = paises.map(p => {
      const ids = filteredUsers.filter(u => u.pais === p).map(u => u.id);
      const pr = relevantProgress.filter(ap => ids.includes(ap.id_usuario));
      const f = pr.filter(x => x.estado_general === PlanState.FORMADO).length;
      const pen = pr.filter(x => x.estado_general === PlanState.PENDIENTE).length;
      return { label: p, val: (f + pen) > 0 ? (f / (f + pen)) * 100 : 0 };
    });

    return { kpi, statsPorPais, formados, pendientes, enProceso, faltaAprobacion, totalFiltrados: userIds.length };
  }, [filters]);

  const renderModuleTabs = () => (
    <div className="flex space-x-1 bg-gray-100 p-1 rounded-2xl mb-8 w-fit shadow-inner">
      {(['COLABORADORES', 'INDICADORES', 'PLANES', 'INGESTA'] as AdminModule[]).map(tab => (
        <button
          key={tab}
          onClick={() => setActiveTab(tab)}
          className={`px-6 py-2.5 rounded-xl text-[11px] font-black uppercase tracking-widest transition-all ${
            activeTab === tab ? 'bg-white text-blue-600 shadow-sm' : 'text-gray-500 hover:text-gray-700'
          }`}
        >
          {tab.replace('_', ' ')}
        </button>
      ))}
    </div>
  );

  const renderFilterBar = () => (
    <div className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-8">
      <div className="space-y-1">
        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest px-1">País</label>
        <select 
          value={filters.pais}
          onChange={(e) => handleFilterChange('pais', e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 text-xs font-bold rounded-xl px-3 py-2 outline-none focus:ring-2 focus:ring-blue-100"
        >
          {uniqueList('pais').map(p => <option key={p} value={p}>{p}</option>)}
        </select>
      </div>
      <div className="space-y-1">
        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest px-1">Unidad Negocio</label>
        <select 
          value={filters.unidadNegocio}
          onChange={(e) => handleFilterChange('unidadNegocio', e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 text-xs font-bold rounded-xl px-3 py-2 outline-none focus:ring-2 focus:ring-blue-100"
        >
          {uniqueList('unidad_negocio').map(u => <option key={u} value={u}>{u}</option>)}
        </select>
      </div>
      <div className="space-y-1">
        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest px-1">Área</label>
        <select 
          value={filters.area}
          onChange={(e) => handleFilterChange('area', e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 text-xs font-bold rounded-xl px-3 py-2 outline-none focus:ring-2 focus:ring-blue-100"
        >
          {['Todos', ...Object.values(UserArea)].map(a => <option key={a} value={a}>{a}</option>)}
        </select>
      </div>
      <div className="space-y-1">
        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest px-1">Tienda / Unidad</label>
        <select 
          value={filters.tienda}
          onChange={(e) => handleFilterChange('tienda', e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 text-xs font-bold rounded-xl px-3 py-2 outline-none focus:ring-2 focus:ring-blue-100"
        >
          {uniqueList('tienda').map(t => <option key={t} value={t}>{t}</option>)}
        </select>
      </div>
      <div className="space-y-1">
        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest px-1">Cargo</label>
        <select 
          value={filters.cargo}
          onChange={(e) => handleFilterChange('cargo', e.target.value)}
          className="w-full bg-gray-50 border border-gray-100 text-xs font-bold rounded-xl px-3 py-2 outline-none focus:ring-2 focus:ring-blue-100"
        >
          {uniqueList('cargo').map(c => <option key={c} value={c}>{c}</option>)}
        </select>
      </div>
      <div className="space-y-1">
        <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest px-1">Cédula</label>
        <input 
          type="text"
          value={filters.cedula}
          onChange={(e) => handleFilterChange('cedula', e.target.value)}
          placeholder="Buscar ID..."
          className="w-full bg-gray-50 border border-gray-100 text-xs font-bold rounded-xl px-3 py-2 outline-none focus:ring-2 focus:ring-blue-100"
        />
      </div>
    </div>
  );

  const renderColaboradores = () => (
    <div className="space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
        <h3 className="font-black text-blue-900 uppercase text-xs tracking-widest">Maestro de Colaboradores</h3>
        <div className="flex space-x-4">
          <input 
            type="text" 
            placeholder="Cédula..." 
            className="text-xs bg-gray-50 border border-gray-100 rounded-lg px-4 py-2 outline-none focus:ring-2 focus:ring-blue-100"
            value={filters.cedula}
            onChange={(e) => handleFilterChange('cedula', e.target.value)}
          />
          <select 
            value={filters.pais}
            onChange={(e) => handleFilterChange('pais', e.target.value)}
            className="bg-gray-50 border border-gray-200 text-xs font-bold rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-100 outline-none"
          >
            <option>Todos</option>
            <option>Venezuela</option>
            <option>Colombia</option>
          </select>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-blue-900/5 border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50 text-[10px] font-black text-gray-400 uppercase tracking-widest border-b">
                <th className="px-6 py-4">País / Tienda</th>
                <th className="px-6 py-4">Colaborador</th>
                <th className="px-6 py-4">Cargo / Ingreso</th>
                <th className="px-6 py-4 text-center">Avance</th>
                <th className="px-6 py-4">Estado</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {collaboratorsData.map(u => (
                <tr key={u.id} className="hover:bg-blue-50/30 transition-colors">
                  <td className="px-6 py-4">
                    <p className="text-[10px] font-black text-blue-600 uppercase mb-0.5">{u.pais}</p>
                    <p className="text-xs font-bold text-gray-500">{u.tienda}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-sm font-black text-gray-800">{u.nombre} {u.apellido}</p>
                    <p className="text-[10px] font-mono text-gray-400">{u.cedula}</p>
                  </td>
                  <td className="px-6 py-4">
                    <p className="text-xs font-bold text-gray-700">{u.cargo}</p>
                    <p className="text-[10px] text-gray-400 font-medium">Desde: {u.fecha_ingreso}</p>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex flex-col items-center">
                      <span className="text-xs font-black text-blue-600 mb-1">{u.progress?.progreso_porcentaje}%</span>
                      <div className="w-20 bg-gray-100 h-1.5 rounded-full overflow-hidden">
                        <div className="bg-blue-600 h-full" style={{ width: `${u.progress?.progreso_porcentaje}%` }}></div>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    {(() => {
                      const st = u.progress?.estado_general;
                      let color = 'bg-gray-100 text-gray-500';
                      let label = st?.replace('_', ' ');
                      if (st === PlanState.FORMADO) color = 'bg-green-100 text-green-700';
                      if (st === PlanState.PENDIENTE) color = 'bg-red-100 text-red-700';
                      if (st === PlanState.EN_PROCESO) color = 'bg-blue-100 text-blue-700';
                      if (st === PlanState.FALTA_APROBACION) color = 'bg-amber-100 text-amber-700 animate-pulse';
                      return (
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-tighter ${color}`}>
                          {label}
                        </span>
                      );
                    })()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const renderIndicadores = () => (
    <div className="space-y-6 animate-in fade-in duration-500">
      {renderFilterBar()}

      {/* KPI Card */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-blue-600 p-6 rounded-3xl shadow-xl shadow-blue-200 text-white">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 opacity-80">Cumplimiento (KPI)</p>
          <h4 className="text-4xl font-black">{stats.kpi.toFixed(1)}%</h4>
          <p className="text-[10px] mt-2 font-bold opacity-60">Formados / (Formados + Pendientes)</p>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 text-gray-400">Certificados</p>
          <h4 className="text-4xl font-black text-green-600">{stats.formados}</h4>
          <p className="text-[10px] mt-2 font-bold text-gray-300">Total Formados</p>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 text-gray-400">Vencidos</p>
          <h4 className="text-4xl font-black text-red-500">{stats.pendientes}</h4>
          <p className="text-[10px] mt-2 font-bold text-gray-300">Fuera de Plazo</p>
        </div>
        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <p className="text-[10px] font-black uppercase tracking-[0.2em] mb-1 text-gray-400">Total Muestra</p>
          <h4 className="text-4xl font-black text-gray-800">{stats.totalFiltrados}</h4>
          <p className="text-[10px] mt-2 font-bold text-gray-300">Usuarios bajo filtro</p>
        </div>
      </div>

      {/* Otros Estados Detalle */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white p-4 rounded-2xl border border-gray-100 flex items-center justify-between">
           <div className="flex items-center space-x-3">
              <div className="h-10 w-10 bg-blue-50 rounded-xl flex items-center justify-center text-blue-600"><IconPlay /></div>
              <div>
                <p className="text-[10px] font-black text-gray-400 uppercase">En Proceso</p>
                <p className="text-xl font-black text-blue-700">{stats.enProceso}</p>
              </div>
           </div>
           <div className="text-right">
              <p className="text-[9px] font-bold text-gray-400">Dentro de plazo</p>
           </div>
        </div>
        <div className="bg-white p-4 rounded-2xl border border-gray-100 flex items-center justify-between">
           <div className="flex items-center space-x-3">
              <div className="h-10 w-10 bg-amber-50 rounded-xl flex items-center justify-center text-amber-600"><IconAlert /></div>
              <div>
                <p className="text-[10px] font-black text-gray-400 uppercase">Falta Aprobación</p>
                <p className="text-xl font-black text-amber-600">{stats.faltaAprobacion}</p>
              </div>
           </div>
           <div className="text-right">
              <p className="text-[9px] font-bold text-gray-400">Pendiente Validar</p>
           </div>
        </div>
      </div>

      {/* Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
          <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 mb-8">Efectividad por País / Segmento</h3>
          <div className="space-y-6">
            {stats.statsPorPais.length > 0 ? stats.statsPorPais.map(s => (
              <div key={s.label}>
                <div className="flex justify-between mb-2">
                  <span className="text-sm font-bold text-gray-700">{s.label}</span>
                  <span className="text-sm font-black text-blue-600">{s.val.toFixed(0)}%</span>
                </div>
                <div className="w-full bg-gray-50 h-3 rounded-full overflow-hidden">
                  <div className="bg-blue-600 h-full transition-all duration-1000" style={{ width: `${s.val}%` }}></div>
                </div>
              </div>
            )) : (
              <div className="text-center py-12 text-gray-400 text-xs font-medium">No hay datos para mostrar con los filtros actuales.</div>
            )}
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm flex flex-col items-center justify-center text-center">
          <div className="relative h-40 w-40 flex items-center justify-center mb-6">
             <svg className="w-full h-full transform -rotate-90">
                <circle cx="80" cy="80" r="70" stroke="currentColor" strokeWidth="12" fill="transparent" className="text-gray-100" />
                <circle cx="80" cy="80" r="70" stroke="currentColor" strokeWidth="12" fill="transparent" 
                        strokeDasharray={440} 
                        strokeDashoffset={440 - (440 * stats.kpi) / 100} 
                        className="text-blue-600 transition-all duration-1000" />
             </svg>
             <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-3xl font-black text-gray-800">{stats.kpi.toFixed(0)}%</span>
                <span className="text-[9px] font-black text-gray-400 uppercase">LOGRADO</span>
             </div>
          </div>
          <h3 className="text-xs font-black uppercase tracking-widest text-gray-400">Eficiencia Global Filtrada</h3>
          <p className="text-[10px] text-gray-300 font-bold mt-2">Muestra de {stats.totalFiltrados} colaboradores</p>
        </div>
      </div>
    </div>
  );

  const renderPlanes = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center mb-4">
        <h3 className="font-black text-blue-950 uppercase text-xs tracking-widest">Gestión de Biblioteca de Planes</h3>
        <button className="bg-blue-600 text-white px-6 py-2 rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg shadow-blue-100">
          + Nuevo Plan
        </button>
      </div>

      {mockPlans.map(plan => (
        <div key={plan.id_plan} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:border-blue-200 transition-colors">
          <div className="flex justify-between items-start mb-6">
            <div>
              <h4 className="text-lg font-black text-gray-800">{plan.cargo_target}</h4>
              <p className="text-[10px] font-mono text-blue-500 font-bold">{plan.id_plan} • {plan.duracion_dias} días</p>
            </div>
            <div className="flex space-x-2">
              <button className="p-2 hover:bg-gray-100 rounded-lg transition-colors"><IconFile /></button>
            </div>
          </div>
          <div className="space-y-3">
            {plan.modulos.map((m, i) => (
              <div key={i} className="flex items-center justify-between p-3 bg-gray-50 rounded-xl border border-gray-100">
                <span className="text-xs font-bold text-gray-700">{m.titulo}</span>
                <span className="text-[10px] bg-white px-2 py-0.5 rounded-full border border-gray-200 font-black text-gray-400">
                  {m.tareas.length} TAREAS
                </span>
              </div>
            ))}
            <button className="w-full py-2 border-2 border-dashed border-gray-200 rounded-xl text-[10px] font-black text-gray-400 uppercase tracking-widest hover:border-blue-400 hover:text-blue-600 transition-all">
              + Añadir Módulo o Curso
            </button>
          </div>
        </div>
      ))}
    </div>
  );

  const handleSimulateIngest = async () => {
    setIsUploading(true);
    setIngestLog(['Iniciando motor Gemini Pro...', 'Extrayendo capas de texto del PDF...', 'Cruzando con biblioteca de PAPs VPO...']);
    const raw = `PLAN: APV-Colombia-2025 Cargo: APV Modulo: Inventario PAP-OPAR-400...`;
    try {
      const result = await smartIngest(raw);
      setIngestPreview(result);
      setIngestLog(p => [...p, 'Estructura validada.', 'Plan listo para despliegue regional.']);
    } catch(e) { 
      setIngestLog(p => [...p, 'Error de conexión.']);
    } finally { setIsUploading(false); }
  };

  const renderIngesta = () => (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white p-12 rounded-[40px] border-4 border-dashed border-blue-50 flex flex-col items-center justify-center space-y-6 hover:border-blue-400 transition-all cursor-pointer group shadow-2xl shadow-blue-900/5">
        <div className="bg-blue-600 h-20 w-20 rounded-3xl flex items-center justify-center text-white shadow-xl shadow-blue-200 group-hover:scale-110 transition-transform">
           <IconUpload />
        </div>
        <div className="text-center">
          <h3 className="text-xl font-black text-blue-950">Ingesta Inteligente con Gemini</h3>
          <p className="text-sm text-gray-400 font-medium max-w-xs mx-auto mt-2">Sube tus planes en Excel o PDF para que la IA los estructure automáticamente.</p>
        </div>
        <button 
          onClick={handleSimulateIngest}
          className="bg-blue-900 text-white px-10 py-3.5 rounded-2xl font-black text-[11px] uppercase tracking-[0.2em] shadow-xl hover:bg-blue-800 transition-all"
        >
          {isUploading ? 'Procesando...' : 'Subir Documento'}
        </button>
      </div>

      {isUploading && (
        <div className="flex items-center justify-center space-x-3 p-4 bg-indigo-50 rounded-2xl text-indigo-700 font-black text-xs animate-pulse">
          <IconPlay /> <span>GEMINI ESTÁ ANALIZANDO TU PLAN...</span>
        </div>
      )}

      {ingestLog.length > 0 && (
        <div className="bg-gray-900 rounded-3xl p-8 font-mono text-[11px] text-green-400 space-y-2 shadow-2xl border-t-4 border-blue-600">
